            MID("{{ $json.date }}"; 1; 4); 
            MID("{{ $json.date }}"; 6; 2); 
            MID("{{ $json.date }}"; 9; 2)
        ) + TIMEVALUE(MID("{{ $json.date }}"; 12; 8))
    ); 
